# evals/eval_core.py: copy and adapt aiec1 eval_core into this project

## Context
The eval harness needs the same `EvalItem / Score / Scorer / run_eval / EvalRunReport / compare_eval_reports` shapes used in the aiec1 project. Rather than importing from that separate repo, we copy and lightly adapt the module here so this project is self-contained. The adaptation adds one field (`tags` typing fix for Python 3.14) and removes the `pandas` dependency in favour of plain `dict` output ŌĆö the harness renders its own table. The original source is `/Users/msharp/projects/aiec1/07_Advanced_Retrievers/lib/eval_core.py`.

## Files
- `evals/__init__.py` (create) ŌĆö empty package marker
- `evals/eval_core.py` (create) ŌĆö adapted copy of aiec1 eval_core

## Implementation steps

1. Create `evals/__init__.py` (empty file).

2. Create `evals/eval_core.py` by copying from the reference and applying these changes:
   - Remove the `pandas` import and replace `case_table() -> pd.DataFrame` with `case_table() -> list[dict]` that returns plain dicts (no pandas required in this project).
   - Keep ALL other public API unchanged: `EvalItem`, `Score`, `ScorerContext`, `ScorerFunction`, `Scorer`, `create_scorer`, `Task`, `EvalRunRow`, `EvalRunReport`, `run_eval`, `compare_eval_reports`.
   - `compare_eval_reports` may return `list[dict]` instead of a DataFrame.

   ```python
   """Eval core ŌĆö adapted from aiec1 lib/eval_core.py.

   Public API (unchanged from original):
       run_eval(name, data, task, scorers) -> EvalRunReport
       EvalRunReport.summary() -> dict[str, float | int | str]
       EvalRunReport.case_table() -> list[dict]   ŌåÉ plain dicts, no pandas
       compare_eval_reports(*reports) -> list[dict]
   """
   from __future__ import annotations

   from collections.abc import Callable, Mapping, Sequence
   from dataclasses import dataclass, field
   from statistics import fmean
   from time import perf_counter
   from typing import Any, TypeAlias


   @dataclass(frozen=True, slots=True)
   class EvalItem:
       id: str
       input: Any
       expected: Any
       tags: tuple[str, ...] = ()
       metadata: Mapping[str, Any] = field(default_factory=dict)

       def __post_init__(self) -> None:
           if not self.id.strip():
               raise ValueError("Every evaluation item needs a stable id.")


   @dataclass(frozen=True, slots=True)
   class Score:
       score: float
       metadata: Mapping[str, Any] = field(default_factory=dict)

       def __post_init__(self) -> None:
           if not 0.0 <= self.score <= 1.0:
               raise ValueError(f"Score must be 0..1, got {self.score}")


   @dataclass(frozen=True, slots=True)
   class ScorerContext:
       item: EvalItem
       output: Any

       @property
       def input(self) -> Any:
           return self.item.input

       @property
       def expected(self) -> Any:
           return self.item.expected


   ScorerFunction: TypeAlias = Callable[[ScorerContext], "Score | float"]


   @dataclass(frozen=True, slots=True)
   class Scorer:
       name: str
       description: str
       scorer: ScorerFunction

       def __post_init__(self) -> None:
           if not self.name.strip():
               raise ValueError("A scorer needs a name.")

       def evaluate(self, context: ScorerContext) -> Score:
           result = self.scorer(context)
           if isinstance(result, Score):
               return result
           if isinstance(result, (int, float)):
               return Score(score=float(result))
           raise TypeError(f"Scorer {self.name!r} must return Score or a number.")


   def create_scorer(name: str, description: str, scorer: ScorerFunction) -> Scorer:
       return Scorer(name=name, description=description, scorer=scorer)


   Task: TypeAlias = Callable[[Any], Any]


   @dataclass(frozen=True, slots=True)
   class EvalRunRow:
       item: EvalItem
       output: Any
       scores: Mapping[str, Score]
       task_latency_ms: float
       scoring_latency_ms: float

       def score(self, scorer_name: str) -> Score:
           try:
               return self.scores[scorer_name]
           except KeyError as e:
               raise KeyError(f"No score named {scorer_name!r}.") from e


   @dataclass(frozen=True, slots=True)
   class EvalRunReport:
       name: str
       scorers: tuple[Scorer, ...]
       rows: tuple[EvalRunRow, ...]

       def summary(self) -> dict[str, float | int | str]:
           if not self.rows:
               raise ValueError("Cannot summarize an empty report.")
           return {
               "evaluation": self.name,
               "cases": len(self.rows),
               **{
                   s.name: fmean(row.score(s.name).score for row in self.rows)
                   for s in self.scorers
               },
               "mean_task_latency_ms": fmean(r.task_latency_ms for r in self.rows),
               "mean_scoring_latency_ms": fmean(r.scoring_latency_ms for r in self.rows),
           }

       def case_table(self) -> list[dict[str, Any]]:
           rows: list[dict[str, Any]] = []
           for row in self.rows:
               table_row: dict[str, Any] = {
                   "case_id": row.item.id,
                   "input": row.item.input,
                   "expected": row.item.expected,
                   "output": row.output,
                   "task_latency_ms": row.task_latency_ms,
               }
               for s in self.scorers:
                   result = row.score(s.name)
                   table_row[s.name] = result.score
                   table_row[f"{s.name}_meta"] = dict(result.metadata)
               rows.append(table_row)
           return rows


   def run_eval(
       name: str,
       *,
       data: Sequence[EvalItem],
       task: Task,
       scorers: Sequence[Scorer],
   ) -> EvalRunReport:
       if not name.strip():
           raise ValueError("Evaluation needs a name.")
       if not data:
           raise ValueError("Evaluation needs at least one item.")
       if not scorers:
           raise ValueError("Evaluation needs at least one scorer.")
       names = [s.name for s in scorers]
       if len(set(names)) != len(names):
           raise ValueError("Scorer names must be unique.")
       rows: list[EvalRunRow] = []
       for item in data:
           t0 = perf_counter()
           output = task(item.input)
           task_ms = (perf_counter() - t0) * 1_000
           t1 = perf_counter()
           ctx = ScorerContext(item=item, output=output)
           scores = {s.name: s.evaluate(ctx) for s in scorers}
           score_ms = (perf_counter() - t1) * 1_000
           rows.append(EvalRunRow(item=item, output=output, scores=scores,
                                  task_latency_ms=task_ms, scoring_latency_ms=score_ms))
       return EvalRunReport(name=name, scorers=tuple(scorers), rows=tuple(rows))


   def compare_eval_reports(*reports: EvalRunReport) -> list[dict[str, Any]]:
       if len(reports) < 2:
           raise ValueError("Compare at least two reports.")
       ref_ids = tuple(r.item.id for r in reports[0].rows)
       ref_scorers = tuple(s.name for s in reports[0].scorers)
       for rpt in reports[1:]:
           if tuple(r.item.id for r in rpt.rows) != ref_ids:
               raise ValueError("All compared reports must use the same ordered data.")
           if tuple(s.name for s in rpt.scorers) != ref_scorers:
               raise ValueError("All compared reports must use the same ordered scorers.")
       summaries = [rpt.summary() for rpt in reports]
       return sorted(summaries, key=lambda d: tuple(d.get(n, 0) for n in ref_scorers), reverse=True)
   ```

3. Write a smoke test `tests/test_eval_core.py`:
   ```python
   from evals.eval_core import EvalItem, Score, Scorer, run_eval, EvalRunReport

   def test_run_eval_basic():
       items = [EvalItem(id="a", input=1, expected=1), EvalItem(id="b", input=2, expected=2)]
       scorer = Scorer(name="exact", description="exact match",
                       scorer=lambda ctx: Score(1.0 if ctx.output == ctx.expected else 0.0))
       report = run_eval("smoke", data=items, task=lambda x: x, scorers=[scorer])
       assert isinstance(report, EvalRunReport)
       s = report.summary()
       assert s["exact"] == 1.0
       assert s["cases"] == 2
   ```

## Acceptance criteria
- [ ] `evals/eval_core.py` exists and imports cleanly with no `pandas` dependency
- [ ] `from evals.eval_core import run_eval, EvalRunReport, Score, Scorer, create_scorer, compare_eval_reports` succeeds
- [ ] `uv run pytest tests/test_eval_core.py -v` passes

## References
- Original source to copy from: `/Users/msharp/projects/aiec1/07_Advanced_Retrievers/lib/eval_core.py`

# frontend/lib/ws.ts + lib/types.ts: typed WebSocket client with reconnect

## Context
`lib/ws.ts` is the browser-side WebSocket client for 1000 Blank White Cards. It connects directly to `wss://backend/ws/{code}`, sends/receives typed JSON envelopes (mirroring `models/ws_messages.py`), stores `player_id` in `localStorage` for reconnect, and exposes a React-friendly hook `useGameSocket`. `lib/types.ts` contains the TypeScript mirrors of the Pydantic models.

## Files
- `frontend/lib/types.ts` (create) ŌĆö TypeScript mirrors of all WS envelope types
- `frontend/lib/ws.ts` (create) ŌĆö typed WebSocket client + React hook

## Implementation steps

1. Create `frontend/lib/types.ts`:

```typescript
// ŌöĆŌöĆŌöĆ client ŌåÆ server ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export type Placement = {
  zone: "self" | "player" | "center";
  target_player_id?: string;
};

export type JoinMsg = { type: "join"; player_id: string | null; name: string };
export type StartMsg = { type: "start" };
export type DrawMsg = { type: "draw" };
export type PlayMsg = {
  type: "play";
  card_id: string;
  placement: Placement;
  chosen_player_id?: string;
};
export type CreateCardMsg = {
  type: "create_card";
  title: string;
  description: string;
};
export type PreviewCardMsg = {
  type: "preview_card";
  title: string;
  description: string;
};
export type EpilogueVoteMsg = {
  type: "epilogue_vote";
  card_id: string;
  keep: boolean;
};

export type ClientMsg =
  | JoinMsg | StartMsg | DrawMsg | PlayMsg
  | CreateCardMsg | PreviewCardMsg | EpilogueVoteMsg;

// ŌöĆŌöĆŌöĆ server ŌåÆ client ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export type CardSnapshot = {
  id: string;
  title: string;
  description: string;
  author_id: string;
  program?: string;
  snippet?: string;
  verdict?: string;
};

export type PlayerSnapshot = {
  id: string;
  name: string;
  score: number;
  hand: CardSnapshot[];
  connected: boolean;
};

export type GameStateSnapshot = {
  lifecycle: "lobby" | "setup" | "playing" | "epilogue" | "ended";
  players: PlayerSnapshot[];
  turn_index: number;
  direction: 1 | -1;
  center_cards: CardSnapshot[];
  house_rules: CardSnapshot[];
  deck_count: number;
};

export type StateMsg = { type: "state"; state: GameStateSnapshot };
export type EffectAppliedMsg = { type: "effect_applied"; log_entry: string };
export type CardInterpretedMsg = {
  type: "card_interpreted";
  card_id: string;
  program?: string;
  snippet?: string;
  verdict: string;
};
export type PreviewResultMsg = {
  type: "preview_result";
  program?: string;
  snippet?: string;
  verdict: string;
};
export type PromptChoiceMsg = {
  type: "prompt_choice";
  card_id: string;
  prompt: string;
  choices: Array<{ player_id: string; name: string }>;
};
export type EpilogueMsg = { type: "epilogue"; cards: CardSnapshot[] };
export type ErrorMsg = { type: "error"; message: string };
export type BrewingMsg = { type: "brewing"; card_id: string };

export type ServerMsg =
  | StateMsg | EffectAppliedMsg | CardInterpretedMsg | PreviewResultMsg
  | PromptChoiceMsg | EpilogueMsg | ErrorMsg | BrewingMsg;
```

2. Create `frontend/lib/ws.ts`:

```typescript
"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { ClientMsg, ServerMsg, GameStateSnapshot } from "./types";

const PLAYER_ID_KEY = "tbwc_player_id";
const WS_URL = process.env.NEXT_PUBLIC_WS_URL ?? "ws://localhost:8000";

export interface GameSocketState {
  gameState: GameStateSnapshot | null;
  log: string[];
  brewing: string | null;      // card_id being interpreted, or null
  previewResult: {
    program?: string;
    snippet?: string;
    verdict: string;
  } | null;
  error: string | null;
  connected: boolean;
  send: (msg: ClientMsg) => void;
}

/**
 * Connects to wss://backend/ws/{code}, handles reconnect, and returns
 * reactive game state.
 *
 * @param code   Room join code
 * @param name   Player display name
 */
export function useGameSocket(code: string, name: string): GameSocketState {
  const wsRef = useRef<WebSocket | null>(null);
  const [gameState, setGameState] = useState<GameStateSnapshot | null>(null);
  const [log, setLog] = useState<string[]>([]);
  const [brewing, setBrewing] = useState<string | null>(null);
  const [previewResult, setPreviewResult] = useState<GameSocketState["previewResult"]>(null);
  const [error, setError] = useState<string | null>(null);
  const [connected, setConnected] = useState(false);

  const send = useCallback((msg: ClientMsg) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(msg));
    }
  }, []);

  useEffect(() => {
    if (!code || !name) return;

    let cancelled = false;
    let retryTimeout: ReturnType<typeof setTimeout>;

    function connect() {
      if (cancelled) return;
      const ws = new WebSocket(`${WS_URL}/ws/${code}`);
      wsRef.current = ws;

      ws.onopen = () => {
        if (cancelled) { ws.close(); return; }
        setConnected(true);
        setError(null);
        // Send join with stored player_id (reconnect) or null (first join)
        const storedId = localStorage.getItem(PLAYER_ID_KEY);
        ws.send(JSON.stringify({ type: "join", player_id: storedId, name }));
      };

      ws.onmessage = (evt) => {
        const msg: ServerMsg = JSON.parse(evt.data as string);
        switch (msg.type) {
          case "state":
            setGameState(msg.state);
            break;
          case "effect_applied":
            setLog((prev) => [...prev, msg.log_entry]);
            setBrewing(null);
            break;
          case "brewing":
            setBrewing(msg.card_id);
            break;
          case "card_interpreted":
            setBrewing(null);
            break;
          case "preview_result":
            setPreviewResult({ program: msg.program, snippet: msg.snippet, verdict: msg.verdict });
            break;
          case "error":
            setError(msg.message);
            break;
          default:
            break;
        }
      };

      ws.onclose = () => {
        setConnected(false);
        if (!cancelled) {
          // Exponential back-off reconnect
          retryTimeout = setTimeout(connect, 2000);
        }
      };

      ws.onerror = () => {
        setError("WebSocket error ŌĆö reconnectingŌĆ”");
      };
    }

    connect();

    return () => {
      cancelled = true;
      clearTimeout(retryTimeout);
      wsRef.current?.close();
    };
  }, [code, name]);

  return { gameState, log, brewing, previewResult, error, connected, send };
}

/** Store player_id in localStorage after a successful join REST call. */
export function storePlayerId(playerId: string): void {
  localStorage.setItem(PLAYER_ID_KEY, playerId);
}

export function clearPlayerId(): void {
  localStorage.removeItem(PLAYER_ID_KEY);
}
```

## Acceptance criteria
- [ ] `tsc --noEmit` in `frontend/` passes with no errors on these two files.
- [ ] `useGameSocket` is a valid React hook: it does not call hooks conditionally, has a cleanup function that closes the WS.
- [ ] `ServerMsg` type union covers all eight server message types.
- [ ] `ClientMsg` type union covers all seven client message types.
- [ ] Compile-time: creating a `PlayMsg` without `card_id` is a TypeScript error.

## References
- `backend/tbwc/models/ws_messages.py` ŌĆö source of truth for message shapes
- `/Users/msharp/projects/aiec1/09_Agent_Servers/frontend/` ŌĆö scaffold base

# p7-wss-cross-origin-verify: Verify WebSocket works cross-origin from Vercel to Render

## Context
WebSocket connections originate from the browser and bypass Vercel's reverse proxy ŌĆö the browser opens a TCP connection directly to the backend's `wss://` URL. Cross-origin WebSocket connections are controlled by the server (FastAPI), not the browser's CORS API. This issue verifies the end-to-end wss path works from the deployed Vercel frontend to the Render backend, and adds a small test helper to the frontend for debugging.

## Files
- `frontend/src/lib/ws-test.ts` (create) ŌĆö browser-console test snippet for wss connectivity
- `docs/deploy/wss-verify.md` (create) ŌĆö steps to verify wss cross-origin works

## Implementation steps

1. Create `frontend/src/lib/ws-test.ts`:
   ```typescript
   /**
    * Paste this into the browser console on the deployed Vercel frontend
    * to verify the WebSocket connection to the backend works cross-origin.
    *
    * Usage (browser console):
    *   import("/lib/ws-test").then(m => m.testWss())
    * Or just run the function inline after copying the file content.
    */
   export function testWss(wsUrl?: string): void {
     const url = wsUrl ?? process.env.NEXT_PUBLIC_WS_URL ?? "wss://tbwc-backend.onrender.com";
     const roomCode = "TEST01";
     const fullUrl = `${url}/ws/${roomCode}`;
     console.log(`[ws-test] connecting to ${fullUrl}`);
     const ws = new WebSocket(fullUrl);

     ws.onopen = () => {
       console.log("[ws-test] OPEN ŌĆö connection established cross-origin");
       ws.send(JSON.stringify({ type: "join", payload: { player_name: "smoke-test" } }));
     };

     ws.onmessage = (evt) => {
       console.log("[ws-test] MESSAGE", JSON.parse(evt.data));
       ws.close();
     };

     ws.onerror = (err) => {
       console.error("[ws-test] ERROR ŌĆö check CORS_ORIGINS on backend", err);
     };

     ws.onclose = (evt) => {
       console.log(`[ws-test] CLOSED code=${evt.code} reason=${evt.reason}`);
     };
   }
   ```

2. Create `docs/deploy/wss-verify.md`:
   ```markdown
   # Verify WebSocket cross-origin connectivity

   ## Background
   Browser WebSocket upgrades are NOT covered by the browser's Fetch CORS API.
   The backend controls WebSocket access by checking the `Origin` header during
   the HTTP upgrade handshake. FastAPI's CORSMiddleware handles this when configured
   with `allow_origins` that includes the Vercel origin.

   ## Verification steps
   1. Open the deployed Vercel URL in Chrome/Firefox
   2. Open DevTools ŌåÆ Console
   3. Run:
      ```javascript
      const ws = new WebSocket("wss://tbwc-backend.onrender.com/ws/TEST01");
      ws.onopen = () => console.log("OPEN");
      ws.onmessage = e => console.log("MSG", e.data);
      ws.onerror = e => console.error("ERR", e);
      ```
   4. Expected: "OPEN" logs within 2s, followed by a server message
   5. If you see ERR: check Render logs for the actual error;
      most common cause is CORS_ORIGINS not including the Vercel origin.

   ## Troubleshooting
   - `ERR` immediately: backend not running ŌĆö check Render dashboard
   - `ERR` after 30s: Render free tier may be sleeping ŌĆö wake it via /health first
   - `403` in Render logs: CORS_ORIGINS doesn't match Vercel URL exactly (check for trailing slash)
   ```

## Acceptance criteria
- [ ] From the deployed Vercel origin, `new WebSocket("wss://tbwc-backend.onrender.com/ws/ROOM")` reaches `onopen` without error
- [ ] Browser DevTools Network tab shows the WebSocket connection as status 101 (Switching Protocols)
- [ ] No "Cross-Origin" or "blocked" errors in browser console
- [ ] `docs/deploy/wss-verify.md` committed with accurate troubleshooting steps

## References
- Reuse: `/tmp/tbwc-issues/phase7/03-cors-config.md` ŌĆö CORS_ORIGINS must include Vercel origin
- Reuse: `/tmp/tbwc-issues/phase3/06-ws-endpoint.md` ŌĆö the /ws/{room_code} route being tested

# frontend/components/effect-log.tsx: live effect log feed

## Context
The effect log is a running feed of game events shown during the "playing" lifecycle. Each time a card effect is applied, the server sends `{ type: "effect_applied", log_entry: "..." }`. The feed also shows brewing indicators when an agent is interpreting a card. This component is a read-only display, receiving `log` (string array) and `brewing` (card_id or null) as props from the room page.

## Files
- `frontend/components/effect-log.tsx` (create) ŌĆö scrolling effect log feed

## Implementation steps

1. Create `frontend/components/effect-log.tsx`:

```tsx
"use client";

import { useEffect, useRef } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";

interface EffectLogProps {
  log: string[];
  /** card_id being interpreted (shows a "thinking" entry) or null */
  brewing: string | null;
  className?: string;
}

export function EffectLog({ log, brewing, className }: EffectLogProps) {
  const bottomRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new entries
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [log.length, brewing]);

  const isEmpty = log.length === 0 && !brewing;

  return (
    <div className={cn("flex flex-col gap-1", className)}>
      <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
        Effect Log
      </p>
      <ScrollArea className="h-40 w-full rounded-lg border bg-muted/20 p-2">
        {isEmpty && (
          <p className="text-xs text-muted-foreground italic">No events yet.</p>
        )}
        {log.map((entry, i) => (
          <div key={i} className="text-xs py-0.5 border-b border-border/40 last:border-0">
            {entry}
          </div>
        ))}
        {brewing && (
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground py-0.5">
            <span className="size-1.5 rounded-full bg-current animate-bounce [animation-delay:-0.3s]" />
            <span className="size-1.5 rounded-full bg-current animate-bounce [animation-delay:-0.15s]" />
            <span className="size-1.5 rounded-full bg-current animate-bounce" />
            <span className="ml-1">Interpreting cardŌĆ”</span>
          </div>
        )}
        <div ref={bottomRef} />
      </ScrollArea>
    </div>
  );
}
```

2. Wire into the `PlayingView` area in `app/room/[code]/page.tsx`:

```tsx
// Replace the stub:
import { EffectLog } from "@/components/effect-log";
// ...
function PlayingView({ gameState, send, log, brewing }: { ... }) {
  return (
    <div className="flex flex-col gap-4">
      {/* GameTable, Hand, HouseRulesZone */}
      <EffectLog log={log} brewing={brewing} />
    </div>
  );
}
```

## Acceptance criteria
- [ ] `tsc --noEmit` passes.
- [ ] Renders "No events yet." when `log` is empty and `brewing` is null.
- [ ] Renders each log entry as its own row.
- [ ] When `brewing` is non-null, shows the bouncing-dots thinking indicator at the bottom.
- [ ] Auto-scrolls to the bottom when a new entry is added.

