```tsx
"use client";

import { useState } from "react";
import type { CardSnapshot, ClientMsg } from "@/lib/types";
import { CardTile } from "./card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

interface EpilogueProps {
  /** Cards from the server's 'epilogue' envelope */
  cards: CardSnapshot[];
  send: (msg: ClientMsg) => void;
}

type VoteChoice = "keep" | "destroy";

export function EpilogueView({ cards, send }: EpilogueProps) {
  // Track local votes: card_id -> "keep" | "destroy"
  const [votes, setVotes] = useState<Record<string, VoteChoice>>({});

  function vote(cardId: string, choice: VoteChoice) {
    setVotes((prev) => ({ ...prev, [cardId]: choice }));
    send({
      type: "epilogue_vote",
      card_id: cardId,
      keep: choice === "keep",
    });
  }

  const allVoted = cards.every((c) => votes[c.id] !== undefined);

  return (
    <div className="flex flex-col gap-6 max-w-2xl mx-auto">
      <div>
        <h2 className="text-xl font-bold">Epilogue ŌĆö Vote on the Cards</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Vote to keep or destroy each card. Kept cards enter the permanent card pool.
          {" "}
          <span className="font-medium">{Object.keys(votes).length}/{cards.length} voted.</span>
        </p>
      </div>

      {cards.length === 0 && (
        <p className="text-muted-foreground italic text-sm">No cards were created this game.</p>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {cards.map((card) => {
          const myVote = votes[card.id];
          return (
            <div
              key={card.id}
              className={cn(
                "rounded-lg border p-3 flex flex-col gap-3",
                myVote === "keep" && "border-green-500/60 bg-green-500/5",
                myVote === "destroy" && "border-destructive/60 bg-destructive/5",
              )}
            >
              <CardTile card={card} className="w-full" />

              <div className="flex gap-2">
                <Button
                  size="sm"
                  variant={myVote === "keep" ? "default" : "outline"}
                  className={cn(myVote === "keep" && "bg-green-600 hover:bg-green-700")}
                  onClick={() => vote(card.id, "keep")}
                >
                  Keep
                </Button>
                <Button
                  size="sm"
                  variant={myVote === "destroy" ? "destructive" : "outline"}
                  onClick={() => vote(card.id, "destroy")}
                >
                  Destroy
                </Button>
                {myVote && (
                  <Badge
                    variant="secondary"
                    className={cn(
                      "ml-auto",
                      myVote === "keep" && "bg-green-100 text-green-800",
                      myVote === "destroy" && "bg-red-100 text-red-800",
                    )}
                  >
                    {myVote}
                  </Badge>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {allVoted && (
        <p className="text-sm text-muted-foreground">
          All votes cast ŌĆö waiting for other playersŌĆ”
        </p>
      )}
    </div>
  );
}
```

