## Implementation steps

1. Create `frontend/components/blank-draw-prompt.tsx`:

```tsx
"use client";

import { useState } from "react";
import type { ClientMsg } from "@/lib/types";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";

interface BlankDrawPromptProps {
  /** card_id of the blank card that was drawn ŌĆö must be filled before play continues */
  blankCardId: string;
  send: (msg: ClientMsg) => void;
  previewResult: {
    program?: string;
    snippet?: string;
    verdict: string;
  } | null;
}

export function BlankDrawPrompt({ blankCardId, send, previewResult }: BlankDrawPromptProps) {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [previewed, setPreviewed] = useState(false);
  const [previewing, setPreviewing] = useState(false);

  // When preview result arrives, mark done
  if (previewResult && previewing) {
    setPreviewing(false);
    setPreviewed(true);
  }

  function handlePreview() {
    if (!title.trim() || !description.trim()) return;
    setPreviewing(true);
    setPreviewed(false);
    send({ type: "preview_card", title: title.trim(), description: description.trim() });
  }

  function handleSubmit() {
    if (!title.trim() || !description.trim()) return;
    // create_card replaces the blank card with authored content
    send({ type: "create_card", title: title.trim(), description: description.trim() });
  }

  const canSubmit = title.trim().length > 0 && description.trim().length > 0;

  return (
    <div className="rounded-lg border-2 border-dashed border-primary bg-primary/5 p-4 flex flex-col gap-3">
      <div>
        <p className="font-semibold text-sm">You drew a blank card!</p>
        <p className="text-xs text-muted-foreground">
          Write the rule before play continues.
        </p>
      </div>

      <Input
        placeholder="Card title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        maxLength={60}
      />
      <Textarea
        placeholder="What does this card do?"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
        rows={3}
        maxLength={300}
      />

      {previewResult && previewed && (
        <div className="rounded border bg-muted/40 p-2 text-xs">
          <span className="font-medium">Effect: </span>
          {previewResult.snippet ?? previewResult.verdict}
        </div>
      )}

      <div className="flex gap-2">
        <Button
          size="sm"
          variant="outline"
          onClick={handlePreview}
          disabled={!canSubmit || previewing}
        >
          {previewing ? "InterpretingŌĆ”" : "Preview"}
        </Button>
        <Button size="sm" onClick={handleSubmit} disabled={!canSubmit}>
          Add to game
        </Button>
      </div>
    </div>
  );
}
```

