# frontend/components/create-card-dialog.tsx: card authoring UI with agent preview

## Context
`CreateCardDialog` lets a player author a new blank card. They type a title and rule description, hit "Preview", and the component sends a `preview_card` message over WebSocket. The server runs the agent and returns a `preview_result` envelope with the interpreted effect and a verdict ("ok" / "invalid"). The player can rewrite and re-preview as many times as they want before hitting "Submit", which sends `create_card`. Used during the setup phase and during blank-draw on the fly.

## Files
- `frontend/components/create-card-dialog.tsx` (create) ŌĆö card authoring dialog with preview loop

## Implementation steps

1. Create `frontend/components/create-card-dialog.tsx`:

```tsx
"use client";

import { useState, useEffect } from "react";
import type { ClientMsg, PreviewResultMsg } from "@/lib/types";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Spinner } from "@/components/ui/spinner";

interface CreateCardDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  send: (msg: ClientMsg) => void;
  /** Latest preview result delivered by useGameSocket */
  previewResult: {
    program?: string;
    snippet?: string;
    verdict: string;
  } | null;
}

export function CreateCardDialog({
  open,
  onOpenChange,
  send,
  previewResult,
}: CreateCardDialogProps) {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [previewing, setPreviewing] = useState(false);
  const [localPreview, setLocalPreview] = useState<typeof previewResult>(null);

  // When we receive a preview_result from the server, stop the spinner
  useEffect(() => {
    if (previewResult && previewing) {
      setPreviewing(false);
      setLocalPreview(previewResult);
    }
  }, [previewResult]);

  function handlePreview() {
    if (!title.trim() || !description.trim()) return;
    setPreviewing(true);
    setLocalPreview(null);
    send({ type: "preview_card", title: title.trim(), description: description.trim() });
  }

  function handleSubmit() {
    if (!title.trim() || !description.trim()) return;
    send({ type: "create_card", title: title.trim(), description: description.trim() });
    // Reset
    setTitle("");
    setDescription("");
    setLocalPreview(null);
    onOpenChange(false);
  }

  function handleClose() {
    setTitle("");
    setDescription("");
    setLocalPreview(null);
    setPreviewing(false);
    onOpenChange(false);
  }

  const canSubmit = title.trim().length > 0 && description.trim().length > 0;
  const verdictOk = localPreview?.verdict === "ok";

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Author a new card</DialogTitle>
        </DialogHeader>

        <div className="flex flex-col gap-3">
          <Input
            placeholder="Card title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            maxLength={60}
          />
          <Textarea
            placeholder="Rule text ŌĆö describe what this card does"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            rows={4}
            maxLength={300}
          />

          {/* Preview result */}
          {previewing && (
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <Spinner className="size-4" />
              <span>Interpreting cardŌĆ”</span>
            </div>
          )}

          {localPreview && !previewing && (
            <div className="rounded-lg border bg-muted/30 p-3 flex flex-col gap-1">
              <div className="flex items-center gap-2">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
                  Interpreted effect
                </p>
                <Badge variant={verdictOk ? "secondary" : "destructive"} className="text-xs">
                  {localPreview.verdict}
                </Badge>
              </div>
              {localPreview.snippet && (
                <p className="text-sm">{localPreview.snippet}</p>
              )}
              {!verdictOk && (
                <p className="text-xs text-destructive">
                  This card's effect couldn't be parsed cleanly. Rewrite the description and preview again.
                </p>
              )}
            </div>
          )}
        </div>

        <DialogFooter className="gap-2">
          <Button variant="outline" size="sm" onClick={handlePreview} disabled={!canSubmit || previewing}>
            Preview effect
          </Button>
          <Button
            size="sm"
            onClick={handleSubmit}
            disabled={!canSubmit}
          >
            Submit card
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
```

Note: `previewResult` comes from `useGameSocket`'s `previewResult` field. The parent page passes it down. The "Submit card" button is always enabled once title+description are filled ŌĆö players can submit without previewing (their call).

