          <CardTile
            key={card.id}
            card={card}
            brewing={card.id === brewingCardId}
            selectable={isMyTurn}
            onClick={() =>
              setSelectedCardId((prev) => (prev === card.id ? null : card.id))
            }
            className={selectedCardId === card.id ? "ring-2 ring-primary" : undefined}
          />
        ))}
        {hand.length === 0 && (
          <p className="text-sm text-muted-foreground italic">No cards in hand</p>
        )}
      </div>

      {/* Play controls ŌĆö only shown when a card is selected and it's your turn */}
