        <div className="flex items-center gap-2 rounded-lg border bg-muted/40 p-3">
          <p className="text-sm font-medium mr-2">Play "{selectedCard.title}"</p>

          {/* Placement picker */}
          <Select value={zone} onValueChange={(v) => setZone(v as Placement["zone"])}>
            <SelectTrigger className="w-36">
              <SelectValue placeholder="Where?" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="self">On myself</SelectItem>
              <SelectItem value="center">Center / rule</SelectItem>
              <SelectItem value="player">On a player</SelectItem>
            </SelectContent>
          </Select>

          {zone === "player" && (
            <Select value={targetPlayerId} onValueChange={setTargetPlayerId}>
              <SelectTrigger className="w-36">
                <SelectValue placeholder="Which player?" />
              </SelectTrigger>
              <SelectContent>
                {otherPlayers.map((p) => (
                  <SelectItem key={p.id} value={p.id}>
                    {p.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          )}

          <Button
            size="sm"
            disabled={zone === "player" && !targetPlayerId}
