## Implementation steps

1. Replace `frontend/app/page.tsx` with:

```tsx
"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { storePlayerId } from "@/lib/ws";

const API_URL = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000";

export default function LandingPage() {
  const router = useRouter();
  const [name, setName] = useState("");
  const [joinCode, setJoinCode] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const nameValid = name.trim().length >= 1;

  async function handleCreate() {
    if (!nameValid) return;
    setLoading(true);
    setError(null);
    try {
      // 1. Create room
      const createRes = await fetch(`${API_URL}/rooms`, { method: "POST" });
      if (!createRes.ok) throw new Error("Failed to create room");
      const { code } = await createRes.json();

      // 2. Join the room we just created
      const joinRes = await fetch(`${API_URL}/rooms/${code}/join`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: name.trim() }),
      });
      if (!joinRes.ok) throw new Error("Failed to join room");
      const { player_id } = await joinRes.json();
      storePlayerId(player_id);

      router.push(`/room/${code}`);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Something went wrong");
    } finally {
      setLoading(false);
    }
  }

  async function handleJoin() {
    if (!nameValid || joinCode.trim().length !== 6) return;
    setLoading(true);
    setError(null);
    try {
      const code = joinCode.trim().toUpperCase();
      const joinRes = await fetch(`${API_URL}/rooms/${code}/join`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: name.trim() }),
      });
      if (!joinRes.ok) {
        const body = await joinRes.json().catch(() => ({}));
        throw new Error(body.detail ?? `Room '${code}' not found`);
      }
      const { player_id } = await joinRes.json();
      storePlayerId(player_id);

      router.push(`/room/${code}`);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Something went wrong");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="flex h-dvh flex-col items-center justify-center gap-6 p-4">
      <div className="text-center">
        <h1 className="text-4xl font-bold tracking-tight">
          1000 Blank White Cards
        </h1>
        <p className="mt-2 text-muted-foreground">
          The card game where you make the rules.
        </p>
      </div>

      <Card className="w-full max-w-sm">
        <CardHeader>
          <CardTitle className="text-lg">Your name</CardTitle>
        </CardHeader>
        <CardContent>
          <Input
            placeholder="Enter your name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            maxLength={24}
          />
        </CardContent>
      </Card>

      <div className="flex w-full max-w-sm flex-col gap-3">
        <Button
          size="lg"
          disabled={!nameValid || loading}
          onClick={handleCreate}
        >
          Create New Room
        </Button>

        <div className="flex gap-2">
          <Input
            placeholder="Room code (6 chars)"
            value={joinCode}
            onChange={(e) => setJoinCode(e.target.value.toUpperCase())}
            maxLength={6}
            className="font-mono uppercase"
          />
          <Button
            disabled={!nameValid || joinCode.trim().length !== 6 || loading}
            onClick={handleJoin}
          >
            Join
          </Button>
        </div>
      </div>

      {error && (
        <p className="text-sm text-destructive">{error}</p>
      )}
    </main>
  );
}
```

